    "target": "ES2022",
    "lib": ["dom", "dom.iterable", "ES2022"],
    "allowJs": true,
    "skipLibCheck": true,
    "strict": true,
    "noEmit": true,
    "esModuleInterop": true,
    "module": "ESNext",
    "moduleResolution": "bundler",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "jsx": "preserve",
    "incremental": true,
    "plugins": [
      {
        "name": "next"
      }
    ],
    "paths": {
      "@/*": ["./src/*"]
    }
  },
  "include": ["next-env.d.ts", "**/*.ts", "**/*.tsx", ".next/types/**/*.ts"],
  "exclude": ["node_modules"]
}
```

### 3. Verify `next.config.js` (if customizing output)
If you are using `next build` directly, ensure no legacy CommonJS flags are interfering. Standard Next.js configs usually handle this, but if you have a custom `output: 'standalone'` or specific bundler config, ensure it doesn't force CommonJS.

**File:** `next.config.js` (or `next.config.ts`)

